wire signed [7:0] x;
assign x = 8'sb0;
wire unsigned [7:0] y = unsigned'(x);
reg unsigned [7:0] r;
always @(posedge clk) r <= y;

logic signed [7:0] reset_val;
logic [7:0] cast_val;
assign cast_val = unsigned'(reset_val);
logic [7:0] reg_q;
always @(posedge clk) reg_q <= cast_val;
